+    fn collect_obligation_finalize_order(&self, id: PlanId, order: &mut Vec<PlanId>) {
+        match self.dag.node(id) {
+            Some(PlanNode::Join { children }) => {
+                for child in children {
+                    self.collect_obligation_finalize_order(*child, order);
+                }
